pub fn send_bits(state: &mut DeflateState, value: u16, length: u8) {
    let len = length as u32;
    let val = value as u32;
    let valid = state.bi_valid as u32;
    // If the new bits fit, just shift in.
    if valid + len > 16 {
        // Flush the low byte, then the high byte of bi_buf before appending.
        state.bi_buf |= (val << valid) as u16;
        state.pending.push((state.bi_buf & 0xff) as u8);
        state.pending.push((state.bi_buf >> 8) as u8);
        // Put the remaining bits of value into the freshly cleared buffer.
        state.bi_buf = (val >> (16 - valid)) as u16;
        state.bi_valid = ((valid + len) - 16) as u8;
    } else {
        state.bi_buf |= (val << valid) as u16;
        state.bi_valid = (valid + len) as u8;
    }
}

pub fn bi_windup(state: &mut DeflateState) {
    if state.bi_valid > 8 {
        state.pending.push((state.bi_buf & 0xff) as u8);
        state.pending.push((state.bi_buf >> 8) as u8);
    } else if state.bi_valid > 0 {
        state.pending.push((state.bi_buf & 0xff) as u8);
    }
    state.bi_buf = 0;
    state.bi_valid = 0;
}

pub fn bi_flush(state: &mut DeflateState) {
    if state.bi_valid == 16 {
        state.pending.push((state.bi_buf & 0xff) as u8);
        state.pending.push((state.bi_buf >> 8) as u8);
        state.bi_buf = 0;
        state.bi_valid = 0;
    } else if state.bi_valid >= 8 {
        state.pending.push((state.bi_buf & 0xff) as u8);
        state.bi_buf >>= 8;
        state.bi_valid -= 8;
    }
}

pub fn gen_codes(tree: &mut [HuffmanNode], max_code: usize, bl_count: &[u16]) {
    let max_bits = bl_count.len() - 1;
    let mut next_code = [0u16; 16];
    let mut code: u16 = 0;
    for bits in 1..=max_bits {
        code = (code + bl_count[bits - 1]) << 1;
        if bits < next_code.len() {
            next_code[bits] = code;
        }
    }
    for n in 0..=max_code {
        let len = tree[n].len as usize;
        if len == 0 { continue; }
        let c = next_code[len];
        next_code[len] = c + 1;
        // Reflected (LSB-first) code per RFC 1951.
        let mut res: u16 = 0;
        let mut code = c;
        for _ in 0..len {
            res = (res << 1) | (code & 1);
            code >>= 1;
        }
        tree[n].code = res;
    }
}
